import Navbar from "./components/Navbar";
import Intro from "./components/Intro";
import AboutMe from "./components/AboutMe";
import React,{useEffect} from "react";
import Projects from "./components/Projects";
import ScrollToTop from "./components/ScrollToTop";

// import {Rout} from 'react-router-dom'
import {Switch,Route,withRouter} from 'react-router';
const App = () =>
{
    useEffect(() => {
        const children = document.querySelectorAll(".styles_navLinks__38tON ul li");
        children.forEach(function (child) {
            // var a = document.getElementById(child);
            child.setAttribute("href", "#aboutme");
            child.addEventListener('click', (e) => {

                    window.scrollTo({
                        top: 400,
                        behavior: 'smooth',
                    })
                }
            );
            // child.addEventListener('click', function(event){
            //     event.preventDefault();
            //     window.scrollTo(document.querySelector('#aboutme').offsetTop);
            //     // $('html, body').animate({
            //     //     scrollTop: $( $.attr(this, 'href') ).offset().top
            //     // }, 500);
            // });
            // child.href = "#aboutme";
            console.log(child);
            child.click();
        });
    },[]);
    return (
        <div>

            {/*<Switch>*/}
            {/*    <Route exact path='/' component={App}>*/}
                    <Navbar/>
                    <Intro/>
                    <AboutMe/>
                    <Projects/>
                    <ScrollToTop/>
            {/*    </Route>*/}
            {/*    <Route path='/about-me' component={AboutMe}/>*/}
            {/*    <Route path='/project' component={App} />*/}
            {/*</Switch>*/}
        </div>

    );
};

export default withRouter(App);
